parameters.jsCode:
const items = $input.all();

if (!items || items.length === 0) {
  return [];
}

// Group by severity
const critical = items.filter(i => i.json.severity === 'CRITICAL');
const high = items.filter(i => i.json.severity === 'HIGH');
const medium = items.filter(i => i.json.severity === 'MEDIUM');
const low = items.filter(i => i.json.severity === 'LOW');

// Combine medium and low into "warning" for display
const warning = [...medium, ...low];

// Build Slack blocks
const blocks = [];

// Header
blocks.push({
  type: "header",
  text: {
    type: "plain_text",
    text: `🚨 Low Stock Alert - ${items.length} Item(s)`
  }
});

blocks.push({ type: "divider" });

// Critical items (🔴)
if (critical.length > 0) {
  blocks.push({
    type: "section",
    text: {
      type: "mrkdwn",
      text: `*🔴 CRITICAL - ${critical.length} items at minimum stock level:*`
    }
  });

  critical.forEach(item => {
    const percentRemaining = item.json.percent_remaining || 
      ((item.json.quantity_on_hand / item.json.reorder_threshold) * 100).toFixed(1);
    const expiryDate = new Date(item.json.expiry_date).toLocaleDateString();

    blocks.push({
      type: "section",
      text: {
        type: "mrkdwn",
        text: `*${item.json.brand_name || item.json.generic_name}*\n` +
              `📍 ${item.json.location_name || 'Unknown Location'}\n` +
              `📦 ${item.json.package_description || 'N/A'}\n` +
              `💊 Stock: *${item.json.quantity_on_hand}* (${percentRemaining}% of threshold)\n` +
              `⚠️ Reorder at: ${item.json.reorder_threshold} | Min: ${item.json.min_stock_level}\n` +
              `🏷️ NDC: ${item.json.package_ndc}\n` +
              `🧪 Lot: ${item.json.lot_number} | Expires: ${expiryDate}`
      }
    });
  });

  blocks.push({ type: "divider" });
}

// High severity items (🟠)
if (high.length > 0) {
  blocks.push({
    type: "section",
    text: {
      type: "mrkdwn",
      text: `*🟠 HIGH - ${high.length} items below 30% threshold:*`
    }
  });

  high.forEach(item => {
    const percentRemaining = item.json.percent_remaining || 
      ((item.json.quantity_on_hand / item.json.reorder_threshold) * 100).toFixed(1);
    const expiryDate = new Date(item.json.expiry_date).toLocaleDateString();

    blocks.push({
      type: "section",
      text: {
        type: "mrkdwn",
        text: `*${item.json.brand_name || item.json.generic_name}*\n` +
              `📦 ${item.json.package_description || 'N/A'}\n` +
              `Stock: ${item.json.quantity_on_hand} (${percentRemaining}%) | Reorder: ${item.json.reorder_threshold} | NDC: ${item.json.package_ndc}\n` +
              `🧪 Lot: ${item.json.lot_number} | Expires: ${expiryDate}`
      }
    });
  });

  blocks.push({ type: "divider" });
}

// Warning items (🟡) - This combines MEDIUM and LOW severity
if (warning.length > 0) {
  blocks.push({
    type: "section",
    text: {
      type: "mrkdwn",
      text: `*🟡 WARNING - ${warning.length} items below threshold:*`
    }
  });

  warning.forEach(item => {
    const drugName = item.json.brand_name || item.json.generic_name;
    const percentRemaining = item.json.percent_remaining || 
      ((item.json.quantity_on_hand / item.json.reorder_threshold) * 100).toFixed(0);

    blocks.push({
      type: "section",
      text: {
        type: "mrkdwn",
        text: `*${drugName}*\nStock: ${item.json.quantity_on_hand} (${percentRemaining}%) | Reorder: ${item.json.reorder_threshold} | NDC: ${item.json.package_ndc}`
      }
    });
  });

  blocks.push({ type: "divider" });
}

// Summary footer
blocks.push({
  type: "context",
  elements: [{
    type: "mrkdwn",
    text: `📊 Total Low Stock Items: *${items.length}* | 🔴 Critical: *${critical.length}* | 🟡 Warning: *${warning.length}*`
  }]
});

// Build alert_data array with all details needed for database inserts
const alert_data = items.map(item => ({
  inventory_id: item.json.inventory_id,
  package_id: item.json.package_id,
  location_id: item.json.location_id,
  quantity_at_alert: item.json.quantity_on_hand,
  reorder_threshold: item.json.reorder_threshold,
  severity: item.json.severity
}));

// Return complete data structure
return [{
  json: {
    blocks: blocks,
    alert_data: alert_data,
    summary: {
      total: items.length,
      critical: critical.length,
      high: high.length,
      medium: medium.length,
      low: low.length,
      warning: warning.length  // Combined count
    },
    alert_timestamp: new Date().toISOString()
  }
}];

