UPDATE inventory
SET last_alert_sent = NOW()
WHERE id IN (
  SELECT (item->>'inventory_id')::INTEGER
  FROM jsonb_array_elements('{{ JSON.stringify($json.alert_data )}}'::jsonb) AS item
);
